```kotlin
import uniffi.binaryoptionstoolsuni.PocketOption
import kotlinx.coroutines.runBlocking
import kotlinx.coroutines.launch
import kotlinx.coroutines.async
import kotlinx.coroutines.awaitAll

fun main() = runBlocking {
    val api = PocketOption.init("YOUR_SESSION_ID")

    // Subscribe to 5-second candles
    val stream = api.subscribe("EURUSD_otc", 5u)

    // Basic loop
    try {
        while (true) {
            val candle = stream.next()
            val direction = if (candle.close > candle.open) "BULL" else "BEAR"
            println(
                "[${candle.timestamp}] ${candle.symbol} $direction " +
                "O=${candle.open} H=${candle.high} L=${candle.low} C=${candle.close}"
            )
        }
    } catch (e: Exception) {
        println("Stream ended: $e")
    } finally {
        api.unsubscribe("EURUSD_otc")
        api.shutdown()
    }

    // Multiple streams in parallel
    val streamEur = api.subscribe("EURUSD_otc", 5u)
    val streamGbp = api.subscribe("GBPUSD_otc", 5u)

    val jobs = listOf(
        async {
            repeat(5) {
                val c = streamEur.next()
                println("[EUR] ${c.close}")
            }
        },
        async {
            repeat(5) {
                val c = streamGbp.next()
                println("[GBP] ${c.close}")
            }
        }
    )
    jobs.awaitAll()
}
```

