        }
    } catch {
        print("Stream ended: \(error)")
    }

    try await api.unsubscribe(asset: "EURUSD_otc")
    try await api.shutdown()

    // Multiple streams in parallel using async let
    let streamEur = try await api.subscribe(asset: "EURUSD_otc", durationSecs: 5)
    let streamGbp = try await api.subscribe(asset: "GBPUSD_otc", durationSecs: 5)

    async let eurTask: Void = {
        for _ in 0..<5 {
            let c = try await streamEur.next()
            print("[EUR] \(c.close)")
