## Go

```go
package main

import (
    "fmt"
    "sync"
    bot "github.com/ChipaDevTeam/BinaryOptionsTools-v2"
)

func main() {
    api, err := bot.PocketOptionInit("YOUR_SESSION_ID")
    if err != nil { panic(err) }
    defer api.Shutdown()

    // Subscribe to 5-second candles
    stream, err := api.Subscribe("EURUSD_otc", 5)
    if err != nil { panic(err) }

    // Basic loop
    for {
        candle, err := stream.Next()
        if err != nil {
            fmt.Printf("Stream ended: %v\n", err)
            break
        }
        dir := "BULL"
        if candle.Close < candle.Open {
            dir = "BEAR"
        }
        fmt.Printf(
            "[%d] %s %s O=%f H=%f L=%f C=%f\n",
            candle.Timestamp, candle.Symbol, dir,
            candle.Open, candle.High, candle.Low, candle.Close,
        )
    }
    api.Unsubscribe("EURUSD_otc")

    // Multiple streams in parallel
    streamEur, _ := api.Subscribe("EURUSD_otc", 5)
    streamGbp, _ := api.Subscribe("GBPUSD_otc", 5)

    var wg sync.WaitGroup

    consume := func(s bot.SubscriptionStream, label string) {
        defer wg.Done()
        for i := 0; i < 5; i++ {
            c, err := s.Next()
            if err != nil { return }
            fmt.Printf("[%s] %f\n", label, c.Close)
        }
    }

    wg.Add(2)
    go consume(streamEur, "EUR")
    go consume(streamGbp, "GBP")
    wg.Wait()
}
