import { PocketOption } from 'binary-options-tools-uni';

async function main() {
    const api = await PocketOption.init('YOUR_SESSION_ID');

    // Subscribe to 5-second candles
    const stream = await api.subscribe('EURUSD_otc', 5);

    // Basic loop
    try {
        while (true) {
            const candle = await stream.next();
            const direction = candle.close > candle.open ? 'BULL' : 'BEAR';
            console.log(
                `[${candle.timestamp}] ${candle.symbol} ${direction} ` +
                `O=${candle.open} H=${candle.high} L=${candle.low} C=${candle.close}`
            );
        }
    } catch (e) {
        console.log(`Stream ended: ${e}`);
    } finally {
        await api.unsubscribe('EURUSD_otc');
        await api.shutdown();
    }

    // Multiple streams in parallel
    const streamEur = await api.subscribe('EURUSD_otc', 5);
    const streamGbp = await api.subscribe('GBPUSD_otc', 5);

    const consume = async (s, label, count) => {
        for (let i = 0; i < count; i++) {
            const c = await s.next();
            console.log(`[${label}] ${c.close}`);
        }
    };

    await Promise.all([
        consume(streamEur, 'EUR', 5),
        consume(streamGbp, 'GBP', 5),
    ]);
}

main();
